  ('judicial-d35ec6db-moex-00414', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲上班遲到，乙向老闆告狀，使甲心生不滿。下班時，甲欲教訓乙，讓乙以後不要愛告狀，未料 甲一個巴掌，竟讓乙摔倒，頭部撞擊路面石塊而亡。關於甲之行為，下列敘述何者正確？', '["成立殺人罪", "成立強暴侮辱致死罪", "成立重傷致死罪", "成立傷害致死罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
